CREATE TABLE IF NOT EXISTS transaction_history (    id               BIGINT AUTO_INCREMENT PRIMARY KEY,    transaction_id   VARCHAR(100),    operation_id     VARCHAR(100),    accounting_date  DATE,    value_date       DATE,    type_enumeration VARCHAR(50),    type_value       VARCHAR(100),    amount           DECIMAL(19,4),    currency         VARCHAR(10),    description      VARCHAR(500),    account_id       BIGINT,    saved_date       TIMESTAMP);